type ToastVariant = 'success' | 'error' | 'warning' | 'info';

type ToastPlacement =
  | 'top-right'
  | 'top-left'
  | 'top-center'
  | 'bottom-right'
  | 'bottom-left'
  | 'bottom-center';

interface Toast {
  id: string;
  variant: ToastVariant;
  message: string;
  description?: string;
  placement: ToastPlacement;
  durationMs: number;
  autoDismiss: boolean;
  createdAt: number;
  ariaRole: 'status' | 'alert';
  action?: {
    label: string;
    onClick: () => void;
  };
}

interface ToastState {
  toasts: Toast[];
  defaultPlacement: ToastPlacement;
  defaultDurationMs: number;
  maxVisible: number;
}
